/**
 * Unit Tests: API Validator
 * Testa validateRequestBody, validateQueryParams, validatePathParams,
 * validateRequest, createValidationError, sanitizeString, SafeString, SafeUrl
 */

// Polyfill Request/Response/Headers for jsdom environment
import { Request as NodeRequest, Response as NodeResponse, Headers as NodeHeaders } from 'undici';

// @ts-expect-error - polyfill for jsdom
if (typeof globalThis.Request === 'undefined') {
  // @ts-expect-error - polyfill
  globalThis.Request = NodeRequest;
}
// @ts-expect-error - polyfill for jsdom
if (typeof globalThis.Response === 'undefined') {
  // @ts-expect-error - polyfill
  globalThis.Response = NodeResponse;
}
// @ts-expect-error - polyfill for jsdom
if (typeof globalThis.Headers === 'undefined') {
  // @ts-expect-error - polyfill
  globalThis.Headers = NodeHeaders;
}

// Mock logger
jest.mock('@/lib/logger', () => ({
  Logger: jest.fn().mockImplementation(() => ({
    debug: jest.fn(),
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  })),
  logger: {
    debug: jest.fn(),
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import {
  validateRequestBody,
  validateQueryParams,
  validatePathParams,
  validateRequest,
  createValidationError,
  sanitizeString,
  SafeString,
  SafeUrl,
} from '@/lib/validation/api-validator';

// Helper: create a NextRequest with JSON body
function createJsonRequest(
  url: string,
  body: unknown,
  method = 'POST'
): NextRequest {
  return new NextRequest(url, {
    method,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
}

// Helper: create a GET NextRequest with query params
function createGetRequest(url: string): NextRequest {
  return new NextRequest(url, { method: 'GET' });
}

describe('API Validator', () => {
  const TestSchema = z.object({
    name: z.string().min(1, 'Nome é obrigatório'),
    age: z.number().int().positive('Idade deve ser positiva'),
  });

  describe('validateRequestBody', () => {
    it('should validate a correct JSON body', async () => {
      const req = createJsonRequest('http://localhost/api/test', {
        name: 'João',
        age: 25,
      });

      const result = await validateRequestBody(req, TestSchema);
      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.name).toBe('João');
        expect(result.data.age).toBe(25);
      }
    });

    it('should reject missing required fields', async () => {
      const req = createJsonRequest('http://localhost/api/test', {
        name: 'João',
        // age missing
      });

      const result = await validateRequestBody(req, TestSchema);
      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.error).toBeTruthy();
        expect(result.response).toBeDefined();
      }
    });

    it('should reject invalid field types', async () => {
      const req = createJsonRequest('http://localhost/api/test', {
        name: 'João',
        age: 'not-a-number',
      });

      const result = await validateRequestBody(req, TestSchema);
      expect(result.success).toBe(false);
    });

    it('should reject empty name', async () => {
      const req = createJsonRequest('http://localhost/api/test', {
        name: '',
        age: 25,
      });

      const result = await validateRequestBody(req, TestSchema);
      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.error).toContain('obrigatório');
      }
    });

    it('should include details when includeDetails is true', async () => {
      const req = createJsonRequest('http://localhost/api/test', {
        name: '',
        age: -1,
      });

      const result = await validateRequestBody(req, TestSchema, { includeDetails: true });
      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.details).toBeDefined();
      }
    });

    it('should handle invalid JSON gracefully', async () => {
      // Create a request with broken body
      const req = new NextRequest('http://localhost/api/test', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: 'not valid json{{{',
      });

      const result = await validateRequestBody(req, TestSchema);
      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.error).toBeTruthy();
      }
    });

    it('should use custom error status', async () => {
      const req = createJsonRequest('http://localhost/api/test', {});
      const result = await validateRequestBody(req, TestSchema, { errorStatus: 422 });
      expect(result.success).toBe(false);
    });
  });

  describe('validateQueryParams', () => {
    const QuerySchema = z.object({
      page: z.coerce.number().int().positive().default(1),
      search: z.string().optional(),
    });

    it('should validate correct query params', () => {
      const req = createGetRequest('http://localhost/api/test?page=2&search=hello');
      const result = validateQueryParams(req, QuerySchema);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.page).toBe(2);
        expect(result.data.search).toBe('hello');
      }
    });

    it('should apply default values', () => {
      const req = createGetRequest('http://localhost/api/test');
      const result = validateQueryParams(req, QuerySchema);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.page).toBe(1);
      }
    });

    it('should reject invalid query params', () => {
      const req = createGetRequest('http://localhost/api/test?page=-5');
      const result = validateQueryParams(req, QuerySchema);

      expect(result.success).toBe(false);
    });
  });

  describe('validatePathParams', () => {
    const IdSchema = z.object({
      id: z.string().uuid('ID inválido'),
    });

    it('should validate correct path params', () => {
      const result = validatePathParams(
        { id: '123e4567-e89b-12d3-a456-426614174000' },
        IdSchema
      );

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.data.id).toBe('123e4567-e89b-12d3-a456-426614174000');
      }
    });

    it('should reject invalid UUID', () => {
      const result = validatePathParams({ id: 'not-a-uuid' }, IdSchema);

      expect(result.success).toBe(false);
      if (!result.success) {
        expect(result.error).toContain('inválido');
      }
    });

    it('should reject missing params', () => {
      const result = validatePathParams({}, IdSchema);
      expect(result.success).toBe(false);
    });
  });

  describe('validateRequest (body + query)', () => {
    const BodySchema = z.object({
      title: z.string().min(1),
    });
    const QuerySchema = z.object({
      format: z.enum(['json', 'xml']).default('json'),
    });

    it('should validate both body and query', async () => {
      const req = createJsonRequest(
        'http://localhost/api/test?format=json',
        { title: 'Test' }
      );

      const result = await validateRequest(req, BodySchema, QuerySchema);

      expect(result.success).toBe(true);
      if (result.success) {
        expect(result.body.title).toBe('Test');
        expect(result.query.format).toBe('json');
      }
    });

    it('should fail if body is invalid', async () => {
      const req = createJsonRequest(
        'http://localhost/api/test?format=json',
        { title: '' } // too short
      );

      const result = await validateRequest(req, BodySchema, QuerySchema);
      expect(result.success).toBe(false);
    });

    it('should fail if query is invalid', async () => {
      const req = createJsonRequest(
        'http://localhost/api/test?format=yaml', // invalid enum
        { title: 'Test' }
      );

      const result = await validateRequest(req, BodySchema, QuerySchema);
      expect(result.success).toBe(false);
    });
  });

  describe('createValidationError', () => {
    it('should create a NextResponse with error message', () => {
      const response = createValidationError('Campo obrigatório');
      expect(response).toBeDefined();
    });

    it('should include details when provided', () => {
      const response = createValidationError(
        'Erro de validação',
        { name: 'Campo obrigatório' },
        422
      );
      expect(response).toBeDefined();
    });
  });

  describe('sanitizeString', () => {
    it('should escape HTML special characters', () => {
      expect(sanitizeString('<script>alert("xss")</script>')).toBe(
        '&lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;'
      );
    });

    it('should escape ampersand', () => {
      expect(sanitizeString('a & b')).toBe('a &amp; b');
    });

    it('should escape single quotes', () => {
      expect(sanitizeString("it's")).toBe('it&#x27;s');
    });

    it('should not modify safe strings', () => {
      expect(sanitizeString('Hello World 123')).toBe('Hello World 123');
    });

    it('should handle empty string', () => {
      expect(sanitizeString('')).toBe('');
    });

    it('should escape all dangerous characters in mixed input', () => {
      const input = '<div class="test">hello & \'world\'</div>';
      const result = sanitizeString(input);
      expect(result).not.toContain('<');
      expect(result).not.toContain('>');
      expect(result).not.toContain('"');
      expect(result).toContain('&lt;');
      expect(result).toContain('&gt;');
    });
  });

  describe('SafeString', () => {
    it('should sanitize input via Zod transform', () => {
      const result = SafeString.parse('<b>bold</b>');
      expect(result).toBe('&lt;b&gt;bold&lt;/b&gt;');
    });

    it('should pass through safe strings', () => {
      const result = SafeString.parse('Hello');
      expect(result).toBe('Hello');
    });
  });

  describe('SafeUrl', () => {
    it('should accept https URLs', () => {
      const result = SafeUrl.parse('https://example.com');
      expect(result).toBe('https://example.com');
    });

    it('should accept http URLs', () => {
      const result = SafeUrl.parse('http://example.com');
      expect(result).toBe('http://example.com');
    });

    it('should reject non-http URLs', () => {
      expect(() => SafeUrl.parse('ftp://example.com')).toThrow();
    });

    it('should reject invalid URLs', () => {
      expect(() => SafeUrl.parse('not-a-url')).toThrow();
    });

    it('should reject javascript: protocol', () => {
      expect(() => SafeUrl.parse('javascript:alert(1)')).toThrow();
    });
  });
});
